#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int tr, dr, ts, ds;
        scanf("%d", &tr);
        int Tr[tr];
        for (int i = 0; i < tr; i++) {
            scanf("%d", &Tr[i]);
        }
        scanf("%d", &dr);
        int Dr[dr];
        for (int i = 0; i < dr; i++) {
            scanf("%d", &Dr[i]);
        }
        scanf("%d", &ts);
        int Ts[ts];
        for (int i = 0; i < ts; i++) {
            scanf("%d", &Ts[i]);
        }
        scanf("%d", &ds);
        int Ds[ds];
        for (int i = 0; i < ds; i++) {
            scanf("%d", &Ds[i]);
        }
        int ramWins = 1;
        for (int i = 0; i < ts; i++) {
            int found = 0;
            for (int j = 0; j < tr; j++) {
                if (Ts[i] == Tr[j]) {
                    found = 1;
                    break;
                }
            }
            if (!found) {
                ramWins = 0;
                break;
            }
        }
        if (ramWins) {
            for (int i = 0; i < ds; i++) {
                int found = 0;
                for (int j = 0; j < dr; j++) {
                    if (Ds[i] == Dr[j]) {
                        found = 1;
                        break;
                    }
                }
                if (!found) {
                    ramWins = 0;
                    break;
                }
            }
        }
        if (ramWins) {
            printf("yes\n");
        } else {
            printf("no\n");
        }
    }
    return 0;
}

