code.Java:
import java.util.HashSet;
import java.util.Scanner;
import java.util.Set;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int tr = scanner.nextInt();
            Set<Integer> Tr = new HashSet<>();
            for (int i = 0; i < tr; i++) {
                Tr.add(scanner.nextInt());
            }
            int dr = scanner.nextInt();
            Set<Integer> Dr = new HashSet<>();
            for (int i = 0; i < dr; i++) {
                Dr.add(scanner.nextInt());
            }
            int ts = scanner.nextInt();
            Set<Integer> Ts = new HashSet<>();
            for (int i = 0; i < ts; i++) {
                Ts.add(scanner.nextInt());
            }
            int ds = scanner.nextInt();
            Set<Integer> Ds = new HashSet<>();
            for (int i = 0; i < ds; i++) {
                Ds.add(scanner.nextInt());
            }
            boolean ramWins = true;
            for (int x : Ts) {
                if (!Tr.contains(x)) {
                    ramWins = false;
                    break;
                }
            }
            if (ramWins) {
                for (int x : Ds) {
                    if (!Dr.contains(x)) {
                        ramWins = false;
                        break;
                    }
                }
            }
            if (ramWins) {
                System.out.println("yes");
            } else {
                System.out.println("no");
            }
        }
    }
}

